<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Http\Kernel::class); $kernel->bootstrap(); $duplicates = App\Models\BackOrder::select("penjualan_id", "barang_id", Illuminate\Support\Facades\DB::raw("COUNT(*) as cnt"))->groupBy("penjualan_id", "barang_id")->having("cnt", ">", 1)->get(); foreach($duplicates as $dup) { $toDelete = App\Models\BackOrder::where("penjualan_id", $dup->penjualan_id)->where("barang_id", $dup->barang_id)->orderBy("created_at", "asc")->skip(1)->take($dup->cnt - 1)->get(); foreach($toDelete as $d) { $d->delete(); } } echo "Duplikat dibersihkan!";
